#include <stdio.h>
#include <stdlib.h>

#define MAX_N 100000

typedef struct {
    int age;
    int rating;
} Chef;

void maxHeapInsert(Chef heap[], int *size, Chef chef) {
    heap[(*size)++] = chef;
    int index = *size - 1;

    while (index > 0) {
        int parentIndex = (index - 1) / 2;
        if (heap[parentIndex].age >= heap[index].age) break;
        Chef temp = heap[parentIndex];
        heap[parentIndex] = heap[index];
        heap[index] = temp;
        index = parentIndex;
    }
}

Chef maxHeapExtractMax(Chef heap[], int *size) {
    Chef maxChef = heap[0];
    heap[0] = heap[--(*size)];
    int index = 0;

    while (1) {
        int leftChildIndex = 2 * index + 1;
        int rightChildIndex = 2 * index + 2;
        int largestIndex = index;

        if (leftChildIndex < *size && heap[leftChildIndex].age > heap[largestIndex].age) {
            largestIndex = leftChildIndex;
        }
        if (rightChildIndex < *size && heap[rightChildIndex].age > heap[largestIndex].age) {
            largestIndex = rightChildIndex;
        }
        if (largestIndex == index) break;

        Chef temp = heap[index];
        heap[index] = heap[largestIndex];
        heap[largestIndex] = temp;
        index = largestIndex;
    }

    return maxChef;
}

void minHeapInsert(Chef heap[], int *size, Chef chef) {
    heap[(*size)++] = chef;
    int index = *size - 1;

    while (index > 0) {
        int parentIndex = (index - 1) / 2;
        if (heap[parentIndex].age <= heap[index].age) break;
        Chef temp = heap[parentIndex];
        heap[parentIndex] = heap[index];
        heap[index] = temp;
        index = parentIndex;
    }
}

Chef minHeapExtractMin(Chef heap[], int *size) {
    Chef minChef = heap[0];
    heap[0] = heap[--(*size)];
    int index = 0;

    while (1) {
        int leftChildIndex = 2 * index + 1;
        int rightChildIndex = 2 * index + 2;
        int smallestIndex = index;

        if (leftChildIndex < *size && heap[leftChildIndex].age < heap[smallestIndex].age) {
            smallestIndex = leftChildIndex;
        }
        if (rightChildIndex < *size && heap[rightChildIndex].age < heap[smallestIndex].age) {
            smallestIndex = rightChildIndex;
        }
        if (smallestIndex == index) break;

        Chef temp = heap[index];
        heap[index] = heap[smallestIndex];
        heap[smallestIndex] = temp;
        index = smallestIndex;
    }

    return minChef;
}

int main() {
    int N;
    scanf("%d", &N);

    Chef youngTeam[MAX_N], oldTeam[MAX_N];
    int youngSize = 0, oldSize = 0;
    int youngRating = 0, oldRating = 0;

    for (int i = 0; i < N; ++i) {
        Chef chef;
        scanf("%d %d", &chef.age, &chef.rating);

        // Add chef to the correct team based on age
        if (youngSize == 0 || (oldSize > 0 && chef.age < oldTeam[0].age)) {
            maxHeapInsert(youngTeam, &youngSize, chef);
            youngRating += chef.rating;
        } else {
            minHeapInsert(oldTeam, &oldSize, chef);
            oldRating += chef.rating;
        }

        // Balance the teams
        if (youngSize > oldSize + 1) {
            Chef oldestYoung = maxHeapExtractMax(youngTeam, &youngSize);
            youngRating -= oldestYoung.rating;
            minHeapInsert(oldTeam, &oldSize, oldestYoung);
            oldRating += oldestYoung.rating;
        } else if (oldSize > youngSize) {
            Chef youngestOld = minHeapExtractMin(oldTeam, &oldSize);
            oldRating -= youngestOld.rating;
            maxHeapInsert(youngTeam, &youngSize, youngestOld);
            youngRating += youngestOld.rating;
        }

        // Output the absolute difference between team ratings
        printf("%d\n", abs(youngRating - oldRating));
    }

    return 0;
}

