const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

let lines = [];
let i = 0;

rl.on('line', (line) => {
    lines.push(line);
});

rl.on('close', () => {
    let N = parseInt(lines[i++]);
    let chefs = [];

    for (let j = 0; j < N; j++) {
        let [age, rating] = lines[i++].split(' ').map(Number);
        chefs.push([age, rating]);
    }

    let youngTeam = [];
    let oldTeam = [];
    let youngRating = 0, oldRating = 0;

    for (let [age, rating] of chefs) {
        // Add chef to the correct team based on age
        if (youngTeam.length === 0 || (oldTeam.length > 0 && age < oldTeam[0][0])) {
            youngTeam.push([-age, rating]);
            youngRating += rating;
        } else {
            oldTeam.push([age, rating]);
            oldRating += rating;
        }

        // Balance the teams
        if (youngTeam.length > oldTeam.length + 1) {
            const oldestYoung = youngTeam.shift();
            youngRating -= oldestYoung[1];
            oldTeam.push([-oldestYoung[0], oldestYoung[1]]);
            oldRating += oldestYoung[1];
        } else if (oldTeam.length > youngTeam.length) {
            const youngestOld = oldTeam.shift();
            oldRating -= youngestOld[1];
            youngTeam.push([-youngestOld[0], youngestOld[1]]);
            youngRating += youngestOld[1];
        }

        // Calculate and output the absolute difference between team ratings
        console.log(Math.abs(youngRating - oldRating));
    }
});
